    crate::arch::selected_isa::context_switch::reset_switch_call_count_for_test();

    state
        .set_thread_kernel_stack(0, 0xA000_0000, 0xA000_4000)
        .expect("boot stack");
    state
        .initialize_thread_kernel_switch_frame(0, 0x1111_0000)
