        abi.map_intent = MAP_READ;
        abi.metadata_ptr = 0x2000;
        abi.metadata_len = V3_MIN_OUTPUT_LEN as u64;
        let req = RecvRequest::from_v3_abi_request(0, &abi).unwrap();
        assert_eq!(req.map_intent, RecvMapIntent::ReadOnly);
