        assert!(
            IPC_ABI_SRC.contains("No kernel-state mutation"),
            "ipc_abi.rs module doc must state no kernel-state mutation"
        );
        assert!(
            IPC_ABI_SRC.contains("No lock acquisition"),
            "ipc_abi.rs module doc must state no lock acquisition"
        );
