    const CMDLINE_SRC: &str = include_str!("../boot_command_line.rs");
    const RUNTIME_SRC: &str = include_str!("../../runtime.rs");
    const TRAP_ENTRY_SRC: &str = include_str!("../../arch/trap_entry.rs");
